const r = await tools.shell_command({"command":"@'
import glob, struct
from pathlib import Path

root = Path.home() / 'AppData/Local/Temp/ectri-v1.3.11-audit'
needles = [
    'bloodpressure', 'blood_pressure', 'heartrate', 'heart_rate', 'spo2',
    'oxygen', 'temperature', 'bodytemp', 'ecg', 'hrv', 'stress', 'health',
    'bluetooth', 'ble', 'watchtiming', 'watchupblood', 'realsil', 'manridy'
]

def uleb(data, offset):
    value = 0
    shift = 0
    while True:
        byte = data[offset]
        offset += 1
        value |= (byte & 0x7f) << shift
        if byte < 0x80:
            return value, offset
        shift += 7

def strings(path):
    data = path.read_bytes()
    count, offset = struct.unpack_from('<II', data, 0x38)
    result = []
    for index in range(count):
        string_offset, = struct.unpack_from('<I', data, offset + index * 4)
        _, start = uleb(data, string_offset)
        end = data.find(b'\0', start)
        if end < 0:
            continue
        raw = data[start:end]
        try:
            text = raw.decode('utf-8', 'replace')
        except Exception:
            continue
        result.append(text)
    return result

for dex in sorted(root.glob('classes*.dex')):
    hits = []
    for text in strings(dex):
        lower = text.lower()
        if any(needle in lower for needle in needles):
            hits.append(text)
    print(f'\n### {dex.name}: {len(hits)} matches')
    for hit in sorted(set(hits), key=str.lower):
        if len(hit) <= 240:
            print(hit)
