const r = await tools.shell_command({"command":"@'
import glob, struct, sys, traceback
from pathlib import Path
try:
    root = Path.home() / 'AppData/Local/Temp/ectri-v1.3.11-audit'
    needles = ['bloodpressure','blood_pressure','heartrate','heart_rate','spo2','oxygen','temperature','bodytemp','ecg','hrv','stress','health','bluetooth','ble','watchtiming','watchupblood','realsil','manridy']
    def uleb(data, offset):
        value = shift = 0
        while True:
            byte = data[offset]; offset += 1
            value |= (byte & 0x7f) << shift
            if byte < 0x80: return value, offset
            shift += 7
    def strings(path):
        data = path.read_bytes()
        count, offset = struct.unpack_from('<II', data, 0x38)
        result = []
        for index in range(count):
            string_offset, = struct.unpack_from('<I', data, offset + index * 4)
            _, start = uleb(data, string_offset)
            end = data.find(b'\0', start)
            if end >= 0: result.append(data[start:end].decode('utf-8','replace'))
        return result
    for dex in sorted(root.glob('classes*.dex')):
        hits = [text for text in strings(dex) if any(needle in text.lower() for needle in needles)]
        print(f'\n### {dex.name}: {len(hits)} matches')
        for hit in sorted(set(hits), key=str.lower):
            if len(hit) <= 240: print(hit)
except Exception:
    traceback.print_exc()
    sys.exit(1)
